import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.B_-t2C-M.js";const u=JSON.parse('{"title":"Stripe Integration","description":"","frontmatter":{},"headers":[],"relativePath":"deployment/stripe.md","filePath":"deployment/stripe.md"}'),r={name:"deployment/stripe.md"};function d(o,e,n,l,p,h){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="stripe-integration" tabindex="-1">Stripe Integration <a class="header-anchor" href="#stripe-integration" aria-label="Permalink to &quot;Stripe Integration&quot;">​</a></h1><p>LaraCommerce uses the <strong>Stripe PHP SDK</strong> for payments, saved cards, 3D Secure, refunds, and dispute handling.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><h3 id="_1-get-api-keys" tabindex="-1">1. Get API Keys <a class="header-anchor" href="#_1-get-api-keys" aria-label="Permalink to &quot;1. Get API Keys&quot;">​</a></h3><p>Log in to your <a href="https://dashboard.stripe.com/apikeys" target="_blank" rel="noreferrer">Stripe Dashboard</a> and copy your keys.</p><p>For development, use the <strong>Test</strong> keys. For production, use <strong>Live</strong> keys.</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">STRIPE_KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=pk_test_xxxxx       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Publishable key (frontend)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">STRIPE_SECRET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=sk_test_xxxxx    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Secret key (backend)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">STRIPE_WEBHOOK_SECRET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=whsec_xxxxx</span></span></code></pre></div><h3 id="_2-configure-webhook" tabindex="-1">2. Configure Webhook <a class="header-anchor" href="#_2-configure-webhook" aria-label="Permalink to &quot;2. Configure Webhook&quot;">​</a></h3><p>In the Stripe Dashboard → <strong>Developers → Webhooks</strong>, add a new endpoint:</p><ul><li><strong>URL:</strong> <code>https://yourdomain.com/api/v1/stripe/webhook</code></li><li><strong>Events to listen:</strong><ul><li><code>payment_intent.succeeded</code></li><li><code>payment_intent.payment_failed</code></li><li><code>payment_intent.requires_action</code></li><li><code>charge.refunded</code></li><li><code>charge.dispute.created</code></li><li><code>refund.updated</code></li></ul></li></ul><p>Copy the <strong>Signing secret</strong> and set it as <code>STRIPE_WEBHOOK_SECRET</code>.</p><h3 id="_3-local-webhook-testing" tabindex="-1">3. Local Webhook Testing <a class="header-anchor" href="#_3-local-webhook-testing" aria-label="Permalink to &quot;3. Local Webhook Testing&quot;">​</a></h3><p>Use the <a href="https://stripe.com/docs/stripe-cli" target="_blank" rel="noreferrer">Stripe CLI</a> to forward events to your local server:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stripe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> listen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --forward-to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8000/api/v1/stripe/webhook</span></span></code></pre></div><p>This outputs a local webhook signing secret — use it as <code>STRIPE_WEBHOOK_SECRET</code> during development.</p><h2 id="test-cards" tabindex="-1">Test Cards <a class="header-anchor" href="#test-cards" aria-label="Permalink to &quot;Test Cards&quot;">​</a></h2><p>Use these test card numbers in development:</p><table tabindex="0"><thead><tr><th>Card Number</th><th>Description</th></tr></thead><tbody><tr><td><code>4242 4242 4242 4242</code></td><td>Success</td></tr><tr><td><code>4000 0025 0000 3155</code></td><td>Requires 3D Secure authentication</td></tr><tr><td><code>4000 0000 0000 9995</code></td><td>Card declined</td></tr></tbody></table><p>Use any future expiry date, any 3-digit CVC, and any postal code.</p><h2 id="features-implemented" tabindex="-1">Features Implemented <a class="header-anchor" href="#features-implemented" aria-label="Permalink to &quot;Features Implemented&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Details</th></tr></thead><tbody><tr><td>Payment Intents</td><td>Full server-side creation with idempotency keys</td></tr><tr><td>Saved Cards</td><td>Cards stored as Stripe Payment Methods linked to Stripe Customers</td></tr><tr><td>3D Secure</td><td><code>requires_action</code> flow with email notification</td></tr><tr><td>Retry Payments</td><td>Failed intent cancelled, new one created</td></tr><tr><td>Refunds</td><td>Full and partial refunds via Stripe API</td></tr><tr><td>Disputes</td><td>Dispute records created from webhook</td></tr><tr><td>Webhook Security</td><td>Signature verification + 48h deduplication</td></tr></tbody></table>`,21)])])}const k=t(r,[["render",d]]);export{u as __pageData,k as default};
